const items = $input.all();
const content = items[0]?.json?.content || items[0]?.json || [];
const pedidos = Array.isArray(content) ? content : [];

if (pedidos.length === 0) return [{ json: { sql: "SELECT 'sem_faturamentos'", count: 0 } }];

const today = new Date().toISOString().split('T')[0];
let sql = `DELETE FROM "TMC_Alberto".airless_faturamentos WHERE data_faturamento = '${today}';\n`;
sql += `DELETE FROM "TMC_Alberto".airless_itens_faturados WHERE data_faturamento = '${today}';\n`;

for (const ped of pedidos) {
  const dataFat = ped.dataEntrada?.split('T')[0] || today;
  const especie = ped.especieDocumento || 'NF';
  const numDoc = ped.numeroDocumento || '';
  const codVendedor = ped.codigoVendedor || '';
  const nomeVendedor = (ped.nomeVendedor || '').replace(/'/g, "''");
  const codCliente = ped.cliente?.codigoCliente || '';
  const nomeCliente = (ped.cliente?.nome || '').replace(/'/g, "''");
  const valorContabil = ped.valorContabil || 0;
  const tel1 = ped.cliente?.telefone1 || '';
  const tel2 = ped.cliente?.telefone2 || '';
  const telCel = ped.cliente?.telefoneCelular || '';
  const codEmpExp = ped.codigoEmpresaExpedicao || '001';
  const qtdItens = (ped.itens || []).length;

  sql += `INSERT INTO "TMC_Alberto".airless_faturamentos (codigo_loja, numero_faturamento, especie_faturamento, data_faturamento, codigo_vendedor, nome_vendedor, codigo_cliente, nome_cliente, valor_contabil, valor_total_itens, quantidade_itens, telefone1, telefone2, telefone_celular, codigo_empresa_expedicao) VALUES ('001', '${numDoc}', '${especie}', '${dataFat}', '${codVendedor}', '${nomeVendedor}', '${codCliente}', '${nomeCliente}', ${valorContabil}, ${valorContabil}, ${qtdItens}, ${tel1 ? "'" + tel1 + "'" : 'NULL'}, ${tel2 ? "'" + tel2 + "'" : 'NULL'}, ${telCel ? "'" + telCel + "'" : 'NULL'}, '${codEmpExp}') ON CONFLICT (codigo_loja, especie_faturamento, numero_faturamento, codigo_empresa_expedicao) DO UPDATE SET valor_contabil = EXCLUDED.valor_contabil, valor_total_itens = EXCLUDED.valor_total_itens, quantidade_itens = EXCLUDED.quantidade_itens, updated_at = now();\n`;

  const itens = ped.itens || [];
  itens.forEach((item, idx) => {
    const codProd = item.codigoProduto || '';
    const descProd = (item.descricaoCompleta || item.descricaoProduto || '').replace(/'/g, "''");
    const codMarca = item.codigoMarca || '';
    const un = item.unidadeProduto || 'UN';
    const qtd = item.quantidade || 0;
    const precoUnit = item.precoUnitario || 0;
    const precoOrig = item.precoOriginal || precoUnit;
    const totalItem = item.totalItem || 0;
    const seq = idx + 1;

    sql += `INSERT INTO "TMC_Alberto".airless_itens_faturados (codigo_loja, numero_faturamento, especie_faturamento, data_faturamento, codigo_vendedor, nome_vendedor, codigo_cliente, nome_cliente, codigo_produto, descricao_produto, codigo_marca, unidade_medida, quantidade, preco_unitario, preco_original, total_item, item_seq) VALUES ('001', '${numDoc}', '${especie}', '${dataFat}', '${codVendedor}', '${nomeVendedor}', '${codCliente}', '${nomeCliente}', '${codProd}', '${descProd}', '${codMarca}', '${un}', ${qtd}, ${precoUnit}, ${precoOrig}, ${totalItem}, ${seq}) ON CONFLICT (codigo_loja, especie_faturamento, numero_faturamento, codigo_produto, item_seq) DO UPDATE SET quantidade = EXCLUDED.quantidade, preco_unitario = EXCLUDED.preco_unitario, total_item = EXCLUDED.total_item, updated_at = now();\n`;
  });
}

return [{ json: { sql, count: pedidos.length } }];

