const today = new Date().toISOString().split('T')[0];
let sql = `DELETE FROM "TMC_Alberto".airless_orcamentos WHERE data_entrada = '${today}';\n`;

function processVendas(pedidos, especie) {
  for (const ped of pedidos) {
    const dataEnt = ped.dataEntrada?.split('T')[0] || today;
    const numDoc = ped.numeroDocumento || '';
    const codVendedor = ped.codigoVendedor || '';
    const nomeVendedor = (ped.nomeVendedor || '').replace(/'/g, "''");
    const codCliente = ped.cliente?.codigoCliente || '';
