      const qtd = item.quantidade || 1;
      const precoUnit = item.precoUnitario || 0;
      const precoOrig = item.precoOriginal || precoUnit;
      const totalItem = item.totalItem || 0;
      const seq = idx + 1;

      sql += `INSERT INTO "TMC_Alberto".airless_orcamentos (numero_documento, especie_documento, codigo_empresa, codigo_vendedor, nome_vendedor, data_entrada, ja_faturado, valor_total, codigo_cliente, nome_cliente, codigo_produto, descricao_produto, codigo_marca, preco_unitario, preco_original, total_item, unidade_medida, quantidade, item_seq, telefone1, telefone2, telefone_celular) VALUES ('${numDoc}', '${especie}', '001', '${codVendedor}', '${nomeVendedor}', '${dataEnt}', ${jaFaturado}, ${totalItem}, '${codCliente}', '${nomeCliente}', '${codProd}', '${descProd}', '${codMarca}', ${precoUnit}, ${precoOrig}, ${totalItem}, '${un}', ${qtd}, ${seq}, ${tel1 ? "'" + tel1 + "'" : 'NULL'}, ${tel2 ? "'" + tel2 + "'" : 'NULL'}, ${telCel ? "'" + telCel + "'" : 'NULL'}) ON CONFLICT (codigo_empresa, especie_documento, numero_documento, codigo_produto, item_seq) DO UPDATE SET preco_unitario = EXCLUDED.preco_unitario, total_item = EXCLUDED.total_item, ja_faturado = EXCLUDED.ja_faturado;\n`;
    });
  }
}

processVendas(orContent, 'OR');
processVendas(pdContent, 'PD');

return [{ json: { sql, countOR: orContent.length, countPD: pdContent.length } }];

